import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// ============================================================================
// AI输入保护+智能纠正
// ============================================================================

const SmartBool = (defVal = false) =>
  z
    .preprocess(val => {
      if (typeof val === 'boolean') return val;
      if (val === null || val === undefined) return false;
      const s = String(val).toLowerCase().trim();
      if (['false', 'no', 'off', '0', '否', '不', '无', 'disable', 'null', 'undefined', ''].includes(s)) return false;
      if (['true', 'yes', 'on', '1', '是', '对', '有', 'enable']. includes(s)) return true;
      return val;
    }, z.boolean())
    .prefault(defVal);

const SmartStr = (defVal = '') =>
  z
    .preprocess(val => {
      if (val === null || val === undefined) return '';
      if (typeof val === 'object') return '';
      return String(val);
    }, z.string())
    .prefault(defVal);

const SafeNum = (defVal = 0) =>
  z
    .union([z.number(), z.string(), z.null(), z.undefined()])
    .transform(val => {
      const n = Number(val);
      return isNaN(n) ? defVal : n;
    })
    .prefault(defVal);

const SafeArr = schema =>
  z. preprocess(val => (Array.isArray(val) ? val : val == null ? [] : [val]), z.array(schema)).prefault([]);

/**
 * 智能对象 (The Void Eater)
 * 核心护盾：将 [], "none", null, undefined -> {}
 * 自带 .catch({}) 和 .prefault({})，确保被包裹的结构绝对安全。
 */

const SmartObj = schema =>
  z
    .preprocess(val => {
      // 核心护盾：将非对象值转为 {}
      if (val === null || val === undefined) return {};
      if (Array.isArray(val)) return {};
      if (typeof val === 'string') {
        const s = val.toLowerCase().trim();
        if (['none', 'null', 'undefined', ''].includes(s)) return {};
      }
      if (typeof val !== 'object') return {};
      // 浅拷贝，确保可扩展
      return { ...val };
    }, schema)
    .prefault({});
// ============================================================================
// 数值定义
// ============================================================================

const NullableMin = min => z.union([z.null(), SafeNum(min).transform(n => Math.max(min, n))]).prefault(null);

const ClampedNum = (min, max) =>
  z
    .union([z.number(), z.string(), z.null(), z.undefined()])
    .transform(val => {
      const n = Number(val);
      if (isNaN(n)) return min;
      return Math.min(max, Math.max(min, n));
    })
    .prefault(min);

// 自定义默认值的区间数值
const ClampedNumWithDefault = (min, max, defVal) =>
  z
    .union([z.number(), z.string(), z.null(), z.undefined()])
    .transform(val => {
      const n = Number(val);
      if (isNaN(n)) return defVal;
      return Math.min(max, Math.max(min, n));
    })
    .prefault(defVal);

const PolymorphicPair = (valSchema, defaultVal) =>
  z
    .preprocess(
      val => {
        if (val === null || val === undefined) return val;

        // 将单一数字扩张为对
        if (typeof val === 'number') {
          return { cur: val, max: val };
        }
        const n = Number(val);
        if (!isNaN(n) && typeof val !== 'object') {
          return { cur: n, max: n };
        }

        // 对象补全
        if (typeof val === 'object') {
          // 若有cur无max，max = cur
          if (val.cur !== undefined && val.max === undefined) {
            return { ...val, max: val.cur };
          }
          // 若有max无当cur，cur = max (防止开局满血变成残血)
          if (val.max !== undefined && val.cur === undefined) {
            return { ...val, cur: val.max };
          }
          return val;
        }
        return val;
      },
      z.object({
        cur: valSchema,
        max: valSchema,
      }),
    )
    .transform(data => {
      // [新增公理]：容器定律
      // 检查两者是否为有效数字，若是，则裁切溢出部分
      if (typeof data.cur === 'number' && typeof data.max === 'number') {
        if (data.cur > data.max) {
          // 观测到溢出：强制坍缩
          data.cur = data.max;
        }
      }
      return data;
    })
    .prefault({});

const StatPair = PolymorphicPair(NullableMin(0), { cur: 0, max: 0 });
const AttributePair = PolymorphicPair(z.number(), { cur: 5, max: 5 });

// 定义货币的单项结构：{ 数量, 单位 }
const CurrencyItem = z
  .object({
    数量: ClampedNum(0, Number.MAX_SAFE_INTEGER),
    单位: SmartStr(''),
  })
  .partial()
  .transform(data => ({
    数量: data?.数量 ?? 0,
    单位: data?.单位 ?? '',
  }))
  .prefault({ 数量: 0, 单位: '' });

// 针对货币的特殊智能转换器
// 它不仅要处理 Object，还要处理 AI 可能输出的 Array<[number, string]> 或 Array<{key: val}>
const SmartCurrency = z.preprocess(val => {
  if (!val || typeof val !== 'object') return {};

  const makeItem = (amount, unit) => ({
    数量: Math.max(0, Number(amount) || 0),
    单位: String(unit ?? ''),
  });

  // 如果已经是对象，归一化为 { 数量, 单位 }
  if (!Array.isArray(val)) {
    return Object.entries(val).reduce((acc, [k, v]) => {
      if (v && typeof v === 'object' && !Array.isArray(v)) {
        const amt = Number(v.数量 ?? v.amount ?? v.value ?? 0);
        const unit = v.单位 ?? v.unit ?? k;
        acc[k] = makeItem(amt, unit);
      } else {
        acc[k] = makeItem(v, k);
      }
      return acc;
    }, {});
  }

  // 如果是数组，尝试将其展平为 Map
  // 处理情况 A: [ ["金币", 100], ["灵魂", 10] ]
  // 处理情况 B: [ { "金币": 100 }, { "灵魂": 10 } ]
  return val.reduce((acc, item) => {
    // 情况 A: 数组项是数组 [Name, Amount] 或 [Amount, Name]
    if (Array.isArray(item)) {
      const [a, b] = item;
      let name, amount;
      // 简单的启发式判断：谁是数字谁是数量
      if (typeof a === 'number') {
        amount = a;
        name = String(b);
      } else {
        name = String(a);
        amount = Number(b) || 0;
      }
      const safeAmt = Math.max(0, amount);
      acc[name] = makeItem(safeAmt, name);
    }
    // 情况 B: 数组项是对象 { "金币": 100 }
    else if (typeof item === 'object' && item !== null) {
      Object.entries(item).forEach(([k, v]) => {
        // 排除无关字段
        if (k === 'ID' || k === 'id') return;
        const amt = Math.max(0, Number(v) || 0);
        if (!isNaN(amt)) {
          acc[k] = makeItem(amt, k);
        }
      });
    }
    return acc;
  }, {});
}, z.record(z.string(), CurrencyItem).prefault({}));

// ============================================================================
// 物品，装备，各项属性定义
// ============================================================================

const BaseAttributes = SmartObj(
  z
    .object({
      力量: AttributePair.prefault({}),
      敏捷: AttributePair.prefault({}),
      感知: AttributePair.prefault({}),
      知识: AttributePair.prefault({}),
      意志: AttributePair.prefault({}),
      魅力: AttributePair.prefault({}),
    })
    .partial(),
);

const TotalAttributes = SmartObj(
  z.object({
    力量: SafeNum(0),
    敏捷: SafeNum(0),
    感知: SafeNum(0),
    知识: SafeNum(0),
    意志: SafeNum(0),
    魅力: SafeNum(0),
  }),
);

const SyncKeyToName = schema =>
  z.record(z.string(), schema).transform(record => {
    Object.entries(record).forEach(([key, item]) => {
      if (item && typeof item === 'object') item.名字 = key;
    });
    return record;
  });

const ITEM_DEFAULTS = defaultType => ({
  名字: '未命名物品',
  类型: defaultType,
  品级: '普通',
  描述: '',
  持握: '单手',
  数量: 1,
  护甲值: 0,
  属性加值: {},
  特殊效果: {},
  伤害: 0, // 防具/饰品缺伤害时默认 0
});

const ItemSchema = defaultType =>
  z.preprocess(
    val => {
      if (val && typeof val === 'object' && val['名称'] && !val['名字']) {
        const { 名称, ...rest } = val;
        return { ...rest, 名字: 名称 }; // 名称 -> 名字
      }
      return val;
    },
    z
      .object({
        名字: SmartStr('未命名物品'),
        类型: SmartStr(defaultType),
        品级: SmartStr('普通'),
        描述: SmartStr(''),
        持握: SmartStr('单手'),
        数量: SafeNum(1),
        护甲值: SafeNum(0),
        属性加值: SmartObj(z.record(z.string(), z.any())),
        特殊效果: SmartObj(z.record(z.string(), z.any())),
        伤害: SafeNum(0),
      })
      .partial() // 允许漏字段
      .transform(data => _.defaultsDeep({}, data, ITEM_DEFAULTS(defaultType))),
  );

const SKILL_DEFAULTS = {
  类型: '未知',
  等级: '初级',
  描述: '',
  消耗: 0,
};

const SkillSchema = z.preprocess(
  val => {
    if (val === null || val === undefined) return {};
    if (typeof val === 'string') return { 描述: val };
    if (typeof val === 'number') return { 消耗: { 体力值: val } };
    return val;
  },

  z
    .object({
      名字: SmartStr('未命名技能'),
      类型: SmartStr('未知'),
      等级: SmartStr('初级'),
      消耗: SmartObj(
        z.object({
          体力值: SafeNum(0),
          生命值: SafeNum(0),
          其他: SmartStr('无'),
        }).prefault({ 体力值: 0, 生命值: 0, 其他: '无' }),
      ),
      判定属性: SmartStr(''),
      检定加值: SafeNum(0),
      描述: SmartStr(''),
    })
    .partial()
    .transform(data => _.defaultsDeep({}, data, {
      名字: '未命名技能',
      类型: '未知',
      等级: '初级',
      消耗: { 体力值: 0, 生命值: 0, 其他: '无' },
      判定属性: '',
      检定加值: 0,
      描述: '',
    })),
);

const EquipmentSlots = SmartObj(
  z.object({
    主武器: z
      .union([z.string(), ItemSchema('武器')])
      .nullable()
      .prefault(null),
    副手: z
      .union([z.string(), ItemSchema('副手')])
      .nullable()
      .prefault(null),
    防具: SmartObj(
      z.object({
        头部: z
          .union([z.string(), ItemSchema('头部防具')])
          .nullable()
          .prefault(null),
        身体: z
          .union([z.string(), ItemSchema('身体防具')])
          .nullable()
          .prefault(null),
        手部: z
          .union([z.string(), ItemSchema('手部防具')])
          .nullable()
          .prefault(null),
        腿部: z
          .union([z.string(), ItemSchema('腿部防具')])
          .nullable()
          .prefault(null),
      }),
    ),
    饰品: z
      .union([z.string(), ItemSchema('饰品')])
      .nullable()
      .prefault(null),
  }),
);

const FactionNode = SmartObj(
  z
    .object({
      影响力: ClampedNumWithDefault(0, 100, 20), // 默认均分 5*20=100
    })
    .prefault({}),
);

const PERSONALITY_DEFAULTS = {
  固定: [],
  动态: [],
};

const PersonalityTags = SmartObj(
  z
    .object({
      固定: SafeArr(z.string()).transform(arr => arr.slice(0, 3)), // 首次写入后三条锁定
      动态: SafeArr(z.string()).transform(arr => arr.slice(-2)), // 始终保留最新 2 条
    })
    .partial()
    .transform(data => _.defaultsDeep({}, data, PERSONALITY_DEFAULTS)),
);

// ============================================================================
// 生命值，体力值，总属性计算器
// ============================================================================

const applyGamePhysics = originalChar => {
  if (!originalChar) return originalChar;

  // [灵魂克隆] 关键：创建浅拷贝，防止因修改不可扩展对象而报错
  const char = { ...originalChar };

  // --- Phase 1: 属性聚合 ---
  const attrKeys = ['力量', '敏捷', '感知', '知识', '意志', '魅力'];
  const stats = {};

  // 1. 提取基础
  const randAttr = () => Math.floor(Math.random() * 12) + 4;

  attrKeys.forEach(key => {
    const baseVal = char.基础属性?.[key];
    let num;

    if (baseVal === undefined || baseVal === null) {
      // 敌人没有提供基础属性时，给 1–20 随机默认
      num = randAttr();
    } else {
      const val = baseVal && typeof baseVal === 'object' ? baseVal.cur : baseVal;
      const n = Number(val);
      num = Number.isFinite(n) ? n : randAttr(); // 非法值也回退随机
    }

    // 确保仍然在 1–20 范围
    stats[key] = Math.min(20, Math.max(1, num));
  });

  // 2. 提取加值 (支持负数)
  const applyBonus = source => {
    if (!source || !source.属性加值) return;
    Object.entries(source.属性加值).forEach(([k, v]) => {
      const targetKey = attrKeys.find(ak => k.includes(ak));
      if (targetKey) {
        const n = parseFloat(String(v)); // 使用 parseFloat 提取 "-5 (Curse)"
        if (!isNaN(n)) {
          stats[targetKey] += n;
        }
      }
    });
  };

  // 3. 扫描装备
  const eq = char.装备栏;
  if (eq) {
    applyBonus(eq.主武器);
    applyBonus(eq.副手);
    applyBonus(eq.饰品);
    if (eq.防具) Object.values(eq.防具).forEach(armor => applyBonus(armor));
  }

  // 4. 扫描状态
  if (char.当前状态) {
    Object.values(char.当前状态).forEach(status => applyBonus(status));
  }

  // 5. 重写总属性
  char.总属性 = { ...char.总属性 };
  attrKeys.forEach(key => {
    char.总属性[key] = Math.max(0, stats[key]);
  });

  // --- Phase 2: 衍生计算 ---
  const str = char.总属性['力量'];
  const will = char.总属性['意志'];
  const agi = char.总属性['敏捷'];

  const newMaxHP = 10 + str * 5 + will * 2;
  const newMaxStamina = 5 + agi + str;

  if (char.生命值) {
    char.生命值 = { ...char.生命值, max: newMaxHP };
    const rawHp = Number(char.生命值.cur);
    const safeHp = Math.max(0, Math.min(isNaN(rawHp) ? newMaxHP : rawHp, newMaxHP));
    char.生命值.cur = safeHp;
  }

  if (char.体力值) {
    char.体力值 = { ...char.体力值, max: newMaxStamina };
    const rawSta = Number(char.体力值.cur);
    const safeSta = Math.max(0, Math.min(isNaN(rawSta) ? newMaxStamina : rawSta, newMaxStamina));
    char.体力值.cur = safeSta;
  }

  return char;
};

// ============================================================================
// 定义NPC和敌人变量基础结构
// 必须定义在 Schema 之前，并使用 SmartObj 包裹以实现自我防御
// ============================================================================
// 

const GrowthSystem = SmartObj(
  z
    .object({
      等级: PolymorphicPair(
        z.coerce.number().transform(n => _.clamp(Math.round(n), 1, 20)),
        { cur: 1, max: 20 },
      ).prefault({}),
      经验值: z
        .preprocess(
          val => {
            if (val === null || val === undefined) return {};
            if (typeof val === 'number') return { cur: val, 升级所需: 100 };
            return val;
          },
          z.object({
            cur: z.coerce.number().transform(n => Math.max(0, n)),
            升级所需: z.coerce.number().transform(n => Math.max(1, n)),
          }),
        )
        .prefault({ cur: 0, 升级所需: 100 }),
      属性点: z.coerce.number().transform(n => Math.max(0, Math.round(n))).prefault(0),
      技能点: z.coerce.number().transform(n => Math.max(0, Math.round(n))).prefault(0),
    })
    .prefault({}),
);


const NPC_DEFAULTS = {
  姓名: '未知者',
  职业: '未知',
  所属区域: '未知',
  是否同伴: false,
  在场: false,
  生命值: { cur: 0, max: 0 },
  护甲值: { cur: 0, max: 0 },
  体力值: { cur: 0, max: 0 },
  基础属性: {
    力量: { cur: 3, max: 20 },
    敏捷: { cur: 3, max: 20 },
    感知: { cur: 3, max: 20 },
    知识: { cur: 3, max: 20 },
    意志: { cur: 3, max: 20 },
    魅力: { cur: 3, max: 20 },
  },
  总属性: {
    力量: 3,
    敏捷: 3,
    感知: 3,
    知识: 3,
    意志: 3,
    魅力: 3,
  },
  装备栏: {},
  当前状态: {},
  身份背景: '',
  性格标签: { 固定: [], 动态: [] },
  外貌: '',
  好感度: 0,
  性趣度: 0,
  性欲度: 0,
  所在地点: '未知',
  重要事件: {},
  技能列表: {},
  成长系统: {
    等级: { cur: 1, max: 20 },
    经验值: { cur: 0, 升级所需: 100 },
    属性点: 0,
    技能点: 0,
  },  
};  

const NpcEntity = SmartObj(
  z
    .object({
      姓名: z.string().min(1),
      职业: SmartStr('未知'),
      所属区域: SmartStr('未知'),
      是否同伴: SmartBool(false),
      在场: SmartBool(false),
      生命值: StatPair.prefault({}),
      护甲值: StatPair.prefault({}),
      体力值: StatPair.prefault({}),
      基础属性: BaseAttributes.prefault({}),
      总属性: TotalAttributes.prefault({}),
      装备栏: EquipmentSlots.prefault({}),
      当前状态: SmartObj(
        z.object({}).catchall(
          z.object({
            描述: SmartStr(''),
            等级: SmartStr('1'),
            属性加值: SmartObj(z.record(z.string(), z.any())),
            特殊效果: SmartObj(z.record(z.string(), z.any())),
            类型: SmartStr('状态'),
          }),
        ),
      ),
      身份背景: SmartStr(''),
      性格标签: PersonalityTags,
      外貌: SmartStr(''),
      好感度: ClampedNumWithDefault(-100, 100, 0),  
      性趣度: ClampedNumWithDefault(0, 100, 0),
      性欲度: ClampedNumWithDefault(0, 100, 0),
      所在地点: SmartStr('未知'),
      重要事件: SmartObj(z.record(z.string(), z.any())),
      技能列表: SmartObj(z.record(z.string(), SkillSchema)),
    })
    .partial() // 允许缺省
    .transform(data => _.defaultsDeep({}, data, NPC_DEFAULTS))
    .transform(applyGamePhysics),
); // <-- 物理引擎在此处生效

const ENEMY_DEFAULTS = {
  类型: '敌对生物',
  生命值: { cur: 0, max: 0 },
  护甲值: { cur: 0, max: 0 },
  基础属性: {},
  总属性: {},
  装备栏: {},
  当前状态: {},
  技能列表: {},
  弱点: '无',
  掉落物: [],
  备注: '',
};

const EnemyEntity = SmartObj(
  z
    .object({
      类型: SmartStr('敌对生物'),
      生命值: StatPair.prefault({}),
      护甲值: StatPair.prefault({}),
      基础属性: BaseAttributes.prefault({}),
      总属性: TotalAttributes.prefault({}),
      装备栏: EquipmentSlots.prefault({}),
      当前状态: SmartObj(
        z.object({}).catchall(
          z.object({
            描述: SmartStr(''),
            等级: SmartStr('1'),
            属性加值: SmartObj(z.record(z.string(), z.any())),
            特殊效果: SmartObj(z.record(z.string(), z.any())),
            类型: SmartStr('状态'),
          }),
        ),
      ),
      技能列表: SmartObj(z.object({}).catchall(SkillSchema)),
      弱点: SmartStr('无'),
      掉落物: SafeArr(z.string()),
      备注: SmartStr(''),
    })
    .partial()
    .transform(data => _.defaultsDeep({}, data, ENEMY_DEFAULTS))
    .transform(applyGamePhysics),
); // <-- 物理引擎在此处生效

// ============================================================================
// 任务系统和新闻列表定义
