const TASK_DEFAULTS = {
  标题: '未命名任务',
  委托类型: '未知',
  风险评估:  '低',
  发布方: '未知',
  报酬:  '未定',
  地点: '未知',
  任务描述: '',
  时限: '无限制',
};

