const FACTION_KEYS = ['执行局', '贸易同盟', '公会', '教会', '贵族'];
const FACTION_UP_LIMIT = 2;
const FACTION_UP_LIMIT_CHURCH = 1;
const FACTION_DOWN_LIMIT = 2;
const RELATION_UP_LIMIT = 5; // 好感/信任上升幅度限制

// ============================================================================
// [NPC守门人] 完整性检查函数
// ============================================================================
const NPC_MIN_ATTR_VALUE = 4; // 基础属性cur必须高于此值，才算"有意写入"而非默认填充

const isNpcComplete = (npcVal) => {
  // 1. 姓名不能是默认值"未知者"，且不能是空
  const name = npcVal?.姓名;
  if (!name || name === '未知者' || name.trim() === '') return false;

  // 2. 职业不能是默认值"未知"
  if (!npcVal?.职业 || npcVal.职业 === '未知') return false;

  // 3. 基础属性六维必须至少有一项被有意写入（cur > 默认兜底3）
  const attrKeys = ['力量', '敏捷', '感知', '知识', '意志', '魅力'];
  const attrs = npcVal?.基础属性;
  if (!attrs) return false;
  const hasRealAttr = attrKeys.some(key => {
    const val = attrs[key]?.cur;
    return typeof val === 'number' && val > NPC_MIN_ATTR_VALUE;
  });
  if (!hasRealAttr) return false;

  return true;
};

await waitGlobalInitialized('Mvu');
// 补全缺失的 stat_data 前缀
eventOn(Mvu.events.COMMAND_PARSED, commands => {
  // 防御性检查：确保 commands 是数组
  if (!commands) return;
  if (!Array.isArray(commands)) {
    commands = [commands]; // 如果是单个对象，转为数组
  }

  commands.forEach(cmd => {
    if (!cmd || !cmd.args) return; // 额外安全检查

    const p0 = cmd.args?.[0];
    if (typeof p0 !== 'string') return;
    const p = p0.trim();

    // JSON Pointer: /xxx/yyy
    if (p.startsWith('/')) {
      if (p === '/stat_data' || p.startsWith('/stat_data/')) return;
      cmd.args[0] = `/stat_data${p}`;
      return;
    }

    // dot-path: xxx.yyy
    if (p === 'stat_data' || p.startsWith('stat_data.')) return;
    cmd.args[0] = `stat_data.${p}`;
  });
});

eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, (newVars, oldVars) => {
  // 势力影响力：方向保持，单次步长限制 + 总和归一化（保留一位小数）
  const oldFaction = _.get(oldVars, 'stat_data.势力影响力', {});
  const incomingFaction = _.get(newVars, 'stat_data.势力影响力', {});

  // 1) 先按步长夹紧
  const entries = FACTION_KEYS.map(key => {
    const oldVal = Number(_.get(oldFaction, [key, '影响力'], 0)) || 0;
    const rawNew = Number(_.get(incomingFaction, [key, '影响力'], oldVal)) || 0;
    const upLimit = key === '教会' ? FACTION_UP_LIMIT_CHURCH : FACTION_UP_LIMIT;
    const clampedDelta = _.clamp(rawNew - oldVal, -FACTION_DOWN_LIMIT, upLimit);
    const val = _.clamp(oldVal + clampedDelta, 0, 100);
    return { key, oldVal, val };
  });

  // 2) 总和归一化到 100，保持方向（增的仍增，减的仍减）
  const getCaps = e => {
    const up = e.key === '教会' ? FACTION_UP_LIMIT_CHURCH : FACTION_UP_LIMIT;
    return {
      hi: Math.min(100, e.oldVal + up),
      lo: Math.max(0, e.oldVal - FACTION_DOWN_LIMIT),
    };
  };

  const normalizeSum = () => {
    // 初始强夹：确保不超出本次上下限
    entries.forEach(e => {
      const { hi, lo } = getCaps(e);
      e.val = Math.min(hi, Math.max(lo, e.val));
    });

    const total = () => entries.reduce((s, e) => s + e.val, 0);

    const adjust = needAdd => {
      const diff = needAdd ? 100 - total() : total() - 100;
      if (diff <= 0.0001) return;

      // 只在还有“空间”的势力间分配
      const pool = entries
        .map(e => {
          const { hi, lo } = getCaps(e);
          const room = needAdd ? hi - e.val : e.val - lo;
          return { e, room };
        })
        .filter(x => x.room > 0.0001);

      if (!pool.length) return; // 没空间直接结束

      const totalRoom = pool.reduce((s, x) => s + x.room, 0) || 1;
      pool.forEach(({ e, room }) => {
        const share = diff * (room / totalRoom);
        const use = Math.min(share, room);
        if (needAdd) e.val += use;
        else e.val -= use;
      });
    };

    if (total() < 100 - 0.0001) adjust(true);
    if (total() > 100 + 0.0001) adjust(false);

    // 收尾：保留一位小数并再次夹紧，最后用微调保证总和=100
    const normalized = {};
    let finalSum = 0;
    entries.forEach(e => {
      const { hi, lo } = getCaps(e);
      e.val = Math.min(hi, Math.max(lo, Number(e.val.toFixed(1))));
      normalized[e.key] = { 影响力: e.val };
      finalSum += e.val;
    });
    const diffFix = Number((100 - finalSum).toFixed(1));
    if (Math.abs(diffFix) > 0.0001) {
      const target =
        entries.find(e => {
          const { hi, lo } = getCaps(e);
          const room = diffFix > 0 ? hi - e.val : e.val - lo;
          return room > 0.0001;
        }) || entries[entries.length - 1];
      const { hi, lo } = getCaps(target);
      const current = normalized[target.key].影响力;
      const room = diffFix > 0 ? hi - current : current - lo;
      const patch = diffFix > 0 ? Math.min(diffFix, room) : Math.max(diffFix, -room);
      normalized[target.key].影响力 = Number((current + patch).toFixed(1));
    }
    _.set(newVars, 'stat_data.势力影响力', normalized);
  };
  normalizeSum();

  // NPC 好感/信任限制（原逻辑不变：老 NPC 上升 ≤5，下降不限；新 NPC 首次 [-100,100]）
  const oldRel = _.get(oldVars, 'stat_data.关系列表', {});
  const newRel = _.get(newVars, 'stat_data.关系列表', {});
  _.forEach(newRel, (npcVal, npcKey) => {
    const oldNpc = oldRel?.[npcKey];

    ['好感度'].forEach(field => {
      const oldVal = Number(_.get(oldNpc, field, 0)) || 0;
      let newVal = Number(_.get(npcVal, field, oldVal));
      if (!Number.isFinite(newVal)) newVal = oldVal;

      if (!oldNpc) {
        // 新 NPC：直接夹紧到 [-100, 100]
        newVal = _.clamp(newVal, -100, 100);
      } else {
        // 老 NPC：上升限制 ≤5，下降不限
        const delta = newVal - oldVal;
        if (delta > RELATION_UP_LIMIT) newVal = oldVal + RELATION_UP_LIMIT;
        newVal = _.clamp(newVal, -100, 100);
      }

      _.set(newVars, ['stat_data', '关系列表', npcKey, field], Number(newVal.toFixed(1)));
    });
  });
  const oldRel2 = _.get(oldVars, 'stat_data.关系列表', {});
  const newRel2 = _.get(newVars, 'stat_data.关系列表', {});

  _.forEach(newRel2, (npcVal, npcKey) => {
    const isNewNpc = !oldRel2?.[npcKey];
    if (isNewNpc && !isNpcComplete(npcVal)) {
      const currentRel = _.get(newVars, 'stat_data.关系列表');
      if (currentRel && typeof currentRel === 'object') {
        delete currentRel[npcKey];
      }
      console.warn(`[NPC守门人] 已拦截不完整的新NPC插入: "${npcKey}"`);
    }
  });
});

